  ('dietitian-moex-04782', 'dietitian', 'dietitian-moex-111-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '根據國民飲食指標當中「多蔬食少紅肉，多粗食少精製」，下列敘述何者錯誤？', '["比起動物性食物，植物性食物對健康較有利，且可降低氣候暖化效應", "比起粗食，精製食物有較多空熱量，且營養素含量較低", "未精製的植物性食物，包括蔬菜、堅果、與白飯", "以烤地瓜取代洋芋片，符合該指標"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:37+00:00", "source_pdf_sha1": "6f5613a1a37b", "answer_pdf_sha1": "0e1aec66d21a", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "103", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04783', 'dietitian', 'dietitian-moex-111-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '某人今日攝取一杯含 15 公克添加糖之珍珠奶茶與一份含 5 公克添加糖的點心，假設他每日熱量 需求為1500大卡。依據民國107年的國民飲食指標建議，下列對於他的飲食建議，何者正確？', '["添加糖攝取熱量占總熱量未超過建議值10%", "添加糖攝取熱量占總熱量未超過建議值15%", "添加糖攝取熱量占總熱量未超過建議值5%", "若總醣類的攝取熱量占總熱量在50～60%範圍，就無須限制添加糖"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:37+00:00", "source_pdf_sha1": "6f5613a1a37b", "answer_pdf_sha1": "0e1aec66d21a", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "103", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
